def test_img_verify_n_store():
    print("🚀 Initializing End-to-End Orchestration Test...")
    
    # Generate mock image payload
    base64_image = generate_dummy_base64_image()
    
    # Construct request payload matching your Pydantic schemas
    payload = {
        "image_base64": base64_image,
        "metadata": {
            "case_id": "TEST-CLAIM-1248",
            "part_category": "Bumper",
            "dealer_id": "DEALER-OWS-79",
            "uploaded_by": "Test_Script"
        },
        "similarity_threshold": 0.85
    }
    
    headers = {"Content-Type": "application/json"}
    
    try:
        print(f"📡 Sending request to Cloud Run: {TARGET_SERVICE_URL}")
        response = requests.post(TARGET_SERVICE_URL, data=json.dumps(payload), headers=headers)
        
        print(f"📥 Response Status Code: {response.status_code}")
        
        if response.status_code == 200:
            print("✅ Service Executed Successfully!")
            print(json.dumps(response.json(), indent=4))
        else:
            print("❌ Service Returned Error:")
            print(response.text)
            
    except Exception as e:
        print(f"💥 Failed to connect to the service: {e}")

if __name__ == "__main__":
    test_img_verify_n_store()